import { Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { ActivatedRoute, Router } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { ReactiveFormsModule, FormBuilder, Validators } from '@angular/forms';
import { map } from 'rxjs/operators';
import { Account } from '../../core/models/crm.models';

@Component({
  selector: 'app-accounts-list',
  standalone: true,
  imports: [CommonModule, RouterLink, ReactiveFormsModule],
  templateUrl: './accounts-list.component.html',
  styleUrl: './accounts-list.component.css',
})
export class AccountsListComponent {
  private route = inject(ActivatedRoute);
  private router = inject(Router);
  private fb = inject(FormBuilder);

  // Backend-provided data. mockup_cleaner empties this; service_agent wires
  // it to AccountService.list() in ngOnInit().
  accounts = signal<Account[]>([
    { id: '1', name: 'Globex Corporation', industry: 'Manufacturing', website: 'globex.com', phone: '+1 415 555 0132' },
    { id: '2', name: 'Initech', industry: 'Software', website: 'initech.io', phone: '+1 512 555 0148' },
    { id: '3', name: 'Umbrella Co', industry: 'Healthcare', website: 'umbrella.co', phone: '+1 212 555 0199' },
    { id: '4', name: 'Soylent Industries', industry: 'Food & Beverage', website: 'soylent.com', phone: '+1 305 555 0170' },
  ]);

  search = signal('');
  filtered = computed(() => {
    const q = this.search().toLowerCase().trim();
    if (!q) return this.accounts();
    return this.accounts().filter(
      (a) => a.name.toLowerCase().includes(q) || a.industry.toLowerCase().includes(q),
    );
  });

  // Modal state is deep-linkable via ?modal=new
  private queryModal = toSignal(
    this.route.queryParamMap.pipe(map((p) => p.get('modal'))),
    { initialValue: this.route.snapshot.queryParamMap.get('modal') },
  );
  showCreate = computed(() => this.queryModal() === 'new');

  form = this.fb.group({
    name: ['', [Validators.required]],
    industry: ['', [Validators.required]],
    website: [''],
    phone: [''],
  });

  onSearch(value: string): void {
    this.search.set(value);
  }

  openCreate(): void {
    this.router.navigate([], { queryParams: { modal: 'new' }, queryParamsHandling: 'merge' });
  }

  closeCreate(): void {
    this.form.reset();
    this.router.navigate([], { queryParams: { modal: null }, queryParamsHandling: 'merge' });
  }

  submit(): void {
    if (this.form.invalid) return;
    const v = this.form.value;
    const account: Account = {
      id: 'tmp-' + this.accounts().length,
      name: v.name!,
      industry: v.industry!,
      website: v.website || undefined,
      phone: v.phone || undefined,
    };
    this.accounts.update((list) => [account, ...list]);
    this.closeCreate();
  }
}
